"use client";
import Link from "next/link";
import { usePathname } from "next/navigation";

const NAV = [
  { href: "/", label: "Dashboard", icon: "▦" },
  { href: "/instances", label: "Endpoints", icon: "▢" },
  { href: "/jobs", label: "Jobs", icon: "⟳" },
];
const MGMT = [
  { href: "/enroll", label: "Enroll", icon: "+" },
];

export default function Sidebar() {
  const pathname = usePathname();
  const isActive = (href: string) =>
    href === "/" ? pathname === "/" : pathname.startsWith(href);

  return (
    <aside className="sidebar">
      <div className="brand">
        <div className="logo">L</div>
        <div className="brand-text">
          Linux Upgrade
          <small>Manager</small>
        </div>
      </div>
      <nav>
        <div className="section-label">Monitor</div>
        {NAV.map((n) => (
          <Link
            key={n.href}
            href={n.href}
            className={isActive(n.href) ? "active" : ""}
          >
            <span className="icon">{n.icon}</span>
            {n.label}
          </Link>
        ))}
        <div className="section-label">Manage</div>
        {MGMT.map((n) => (
          <Link
            key={n.href}
            href={n.href}
            className={isActive(n.href) ? "active" : ""}
          >
            <span className="icon">{n.icon}</span>
            {n.label}
          </Link>
        ))}
      </nav>
      <div className="footer">v0.1.0 · self-hosted</div>
    </aside>
  );
}
